"use server";

import { createClient } from "@/lib/supabase/server";
import {
  getUserFromClaims,
  type AuthActionResult,
  type LoginFormData,
  type SignupFormData,
} from "@/types/authtypes";
import { redirect } from "next/navigation";

const PROFILES_TABLE = "profiles";

export async function signInWithEmail(
  data: LoginFormData,
): Promise<AuthActionResult> {
  const supabase = await createClient();
  const {
    data: { user },
    error,
  } = await supabase.auth.signInWithPassword({
    email: data.email,
    password: data.password,
  });
  if (error || !user) {
    return { ok: false, message: error?.message };
  }
  return { ok: true, redirect: "/dashboard" };
}

export async function signUpWithEmail(
  data: SignupFormData,
): Promise<AuthActionResult> {
  const supabase = await createClient();
  const { error } = await supabase.auth.signUp({
    email: data.email,
    password: data.password,
    options: {
      data: {
        full_name: data.name,
      },
    },
  });
  if (error) {
    return { ok: false, message: error?.message };
  }
  return { ok: true, redirect: "/confirm" };
}

export async function getUserAccessToken(): Promise<
  { token: string } | { message: string; redirect: string }
> {
  const supabase = await createClient();
  try {
    const {
      data: { session },
      error,
    } = await supabase.auth.getSession();
    if (error || !session) {
      return {
        message: error?.message ?? "Failed to get session",
        redirect: "/",
      };
    }
    return { token: session.access_token };
  } catch (err: unknown) {
    if (err instanceof Error) {
      return { message: err.message, redirect: "/" };
    }
    return { message: "Unknown error", redirect: "/" };
  }
}

export async function getUserClaims(): Promise<{
  user: ReturnType<typeof getUserFromClaims>;
} | null> {
  const supabase = await createClient();
  try {
    const { data, error } = await supabase.auth.getClaims();
    if (error || !data?.claims) {
      return null;
    }

    return {
      user: getUserFromClaims(data.claims as Record<string, unknown>),
    };
  } catch {
    return null;
  }
}
export async function getUserProfile(userId: string): Promise<{
  user: {
    id: string;
    email: string;
    full_name: string;
    avatar_url: string;
  };
} | null> {
  const supabase = await createClient();
  const { data, error } = await supabase
    .from(PROFILES_TABLE)
    .select("id, email, full_name, avatar_url")
    .eq("id", userId)
    .single();
  if (error || !data) {
    return null;
  }
  return {
    user: {
      id: data.id,
      email: data.email,
      full_name: data.full_name,
      avatar_url: data.avatar_url,
    },
  };
}

export async function signOut(): Promise<void> {
  const supabase = await createClient();
  const { error } = await supabase.auth.signOut();
  if (error) {
    throw new Error(error?.message);
  }
  redirect("/");
}
